import React from 'react';
import LayoutEstudiante from './LayoutEstudiante';
import { IconoMapa, IconoDolar, IconoRayo } from '../../componentes/Iconos';

const DetalleOferta = ({ oferta, onBack, onLogout }) => {
  // Animación simple de entrada
  const [cargando, setCargando] = React.useState(true);

  React.useEffect(() => {
    const timer = setTimeout(() => setCargando(false), 300);
    return () => clearTimeout(timer);
  }, []);

  if (!oferta) return null;

  return (
    <LayoutEstudiante onLogout={onLogout}>
      <div className={`detalle-oferta-container ${!cargando ? 'visible' : ''}`}>
        <button className="back-btn" onClick={onBack}>
          ← Volver a las ofertas
        </button>

        <div className="detalle-header">
          <div className="company-logo-large">{oferta.empresa[0]}</div>
          <div className="header-info">
            <h1>{oferta.titulo}</h1>
            <div className="header-meta">
              <span className="company-text">{oferta.empresa}</span>
              <span className="dot">•</span>
              <span className="post-date">Publicado hace 2 días</span>
            </div>
          </div>
          <div className="header-actions">
             {oferta.estaSeleccionado ? (
                <span className="match-badge-success-large">Match Confirmado</span>
             ) : (
                <button className="apply-btn-large">
                  Postularme Ahora
                </button>
             )}
          </div>
        </div>

        <div className="detalle-grid">
          <div className="detalle-main-info">
            <section className="detalle-section">
              <h3>Sobre la posición</h3>
              <p>Estamos buscando un perfil con hambre de aprender y crecer en una de las empresas con mayor proyección tecnológica del sector. Formarás parte de un equipo multidisciplinar trabajando en proyectos de alto impacto.</p>
            </section>

            <section className="detalle-section">
              <h3>Requisitos</h3>
              <ul className="detalle-list">
                <li>Estudiante de últimos semestres de Ing. en Software o similar.</li>
                <li>Conocimientos básicos en React, Node.js y bases de datos SQL.</li>
                <li>Pasión por la resolución de problemas técnicos complejos.</li>
                <li>Capacidad para trabajar en equipo y buena comunicación.</li>
              </ul>
            </section>

            <section className="detalle-section">
              <h3>¿Qué ofrecemos?</h3>
              <p>Oportunidad de crecimiento real, horario flexible para sustentar tus estudios, mentoría personalizada y un ambiente de trabajo dinámico y joven.</p>
            </section>
          </div>

          <aside className="detalle-sidebar-info">
            <div className="info-card">
              <div className="info-item">
                <IconoMapa />
                <div>
                  <span className="label">Ubicación</span>
                  <span className="value">{oferta.ubicacion}</span>
                </div>
              </div>
              <div className="info-item">
                <IconoDolar />
                <div>
                  <span className="label">Salario Sugerido</span>
                  <span className="value">{oferta.salario}</span>
                </div>
              </div>
              <div className="info-item">
                <IconoRayo />
                <div>
                  <span className="label">Modalidad</span>
                  <span className="value">{oferta.modalidad}</span>
                </div>
              </div>
            </div>

            <div className="company-side-card">
              <h4>Sobre Tech Innovators</h4>
              <p>Empresa líder en desarrollo de soluciones de software escalables para el sector financiero en toda Latinoamérica.</p>
              <button className="secondary-btn">Ver Perfil Empresa</button>
            </div>
          </aside>
        </div>
      </div>

      <style jsx>{`
        .detalle-oferta-container {
          opacity: 0;
          transform: translateY(10px);
          transition: all 0.4s ease-out;
        }
        .detalle-oferta-container.visible {
          opacity: 1;
          transform: translateY(0);
        }
        .back-btn {
          background: none;
          border: none;
          color: #6366f1;
          font-weight: 600;
          cursor: pointer;
          margin-bottom: 24px;
          padding: 0;
          font-size: 0.95rem;
        }
        .detalle-header {
          display: flex;
          align-items: center;
          gap: 24px;
          margin-bottom: 40px;
          background: white;
          padding: 32px;
          border-radius: 24px;
          border: 1px solid #e2e8f0;
        }
        .company-logo-large {
          width: 80px;
          height: 80px;
          background: #f1f5f9;
          border-radius: 20px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 2rem;
          font-weight: 800;
          color: #2563eb;
        }
        .header-info { flex: 1; }
        .header-info h1 { font-size: 2rem; margin-bottom: 8px; color: #1e293b; }
        .header-meta { display: flex; align-items: center; gap: 12px; color: #64748b; font-weight: 500; }
        .dot { color: #cbd5e1; }
        .apply-btn-large {
          padding: 14px 32px;
          background: linear-gradient(135deg, #2563eb 0%, #6366f1 100%);
          color: white;
          border: none;
          border-radius: 14px;
          font-weight: 700;
          cursor: pointer;
          font-size: 1rem;
          box-shadow: 0 4px 12px rgba(37, 99, 235, 0.25);
        }
        .detalle-grid { display: grid; grid-template-columns: 1fr 320px; gap: 32px; }
        .detalle-section { margin-bottom: 40px; }
        .detalle-section h3 { font-size: 1.25rem; margin-bottom: 16px; color: #1e293b; font-weight: 700; }
        .detalle-section p { line-height: 1.7; color: #475569; }
        .detalle-list { list-style: none; padding: 0; margin: 0; }
        .detalle-list li { margin-bottom: 12px; color: #475569; display: flex; gap: 10px; }
        .detalle-list li::before { content: "•"; color: #2563eb; font-weight: bold; }

        .info-card { background: white; padding: 24px; border-radius: 24px; border: 1px solid #e2e8f0; margin-bottom: 24px; }
        .info-item { display: flex; gap: 16px; margin-bottom: 20px; }
        .info-item .label { display: block; font-size: 0.8rem; color: #94a3b8; font-weight: 600; text-transform: uppercase; }
        .info-item .value { display: block; font-weight: 700; color: #1e293b; margin-top: 2px; }

        .company-side-card { background: #eff6ff; padding: 24px; border-radius: 24px; border: 1px solid rgba(37, 99, 235, 0.1); }
        .company-side-card h4 { margin-bottom: 12px; color: #1e293b; }
        .company-side-card p { font-size: 0.9rem; color: #475569; line-height: 1.5; margin-bottom: 16px; }
        .secondary-btn { width: 100%; padding: 10px; background: white; border: 1px solid #e2e8f0; border-radius: 12px; font-weight: 600; cursor: pointer; color: #1e293b; }
      `}</style>
    </LayoutEstudiante>
  );
};

export default DetalleOferta;
